 10→/// Status of a tag in diff mode
 11→#[derive(Clone, Debug, PartialEq)]
 12→pub enum DiffStatus {
 13→    Unchanged,
 14→    Added,   // In modified but not baseline
 15→    Deleted, // In baseline but not modified
 16→    Changed, // Same tag, different value
 17→}
 18→
 19→/// Represents a single DICOM tag with its properties
 20→#[derive(Clone, Debug)]
 21→pub struct DicomTag {
 22→    /// Tag in (GGGG,EEEE) hex format
 23→    pub tag: String,
 24→    /// Human-readable tag name
 25→    pub name: String,
 26→    /// Value Representation (e.g., "PN", "CS", "LO")
 27→    pub vr: String,
 28→    /// The tag value, truncated if longer than 256 characters
 29→    pub value: String,
 30→    /// Baseline value for changed tags in diff mode (None otherwise)
 31→    pub baseline_value: Option<String>,
 32→    /// Nesting level (0 = root)
 33→    pub depth: usize,
 34→    /// True if this tag has children (is a sequence)
 35→    pub is_expandable: bool,
 36→    /// Current expansion state
 37→    pub is_expanded: bool,
 38→    /// Nested sequence items
 39→    pub children: Vec<DicomTag>,
 40→    /// Diff status (None in normal mode, Some(status) in diff mode)
 41→    pub diff_status: Option<DiffStatus>,
 42→}
 43→
 44→impl DicomTag {
 45→    pub fn is_private(&self) -> bool {
 46→        self.tag
 47→            .get(1..5)
 48→            .and_then(|s| u16::from_str_radix(s, 16).ok())
 49→            .map(|group| group % 2 == 1)
 50→            .unwrap_or(false)
 51→    }
 52→}
 53→
 54→pub fn load_dicom_file<P: AsRef<Path>>(
 55→    path: P,
 56→) -> Result<Vec<DicomTag>, Box<dyn std::error::Error>> {
 57→    let obj = open_file(path)?;
 58→    Ok(extract_tags(&obj))
 59→}
 60→
 61→/// Compare two DICOM files and return tags with diff status
 62→pub fn compare_dicom_files<P: AsRef<Path>>(
 63→    baseline_path: P,
 64→    modified_path: P,
 65→) -> Result<Vec<DicomTag>, Box<dyn std::error::Error>> {
 66→    let baseline_tags = load_dicom_file(baseline_path)?;
 67→    let modified_tags = load_dicom_file(modified_path)?;
 68→
 69→    // Build a map of baseline tags by tag ID (only root-level tags, sequences treated as units)
 70→    let mut baseline_map: HashMap<String, &DicomTag> = HashMap::new();
 71→    for tag in &baseline_tags {
 72→        baseline_map.insert(tag.tag.clone(), tag);
 73→    }
 74→
 75→    // Track which tags from baseline we've seen
 76→    let mut baseline_seen: std::collections::HashSet<String> = std::collections::HashSet::new();
 77→
 78→    // Process modified tags and compare with baseline
 79→    let mut result_tags: Vec<DicomTag> = Vec::new();
 80→
 81→    for modified_tag in &modified_tags {
 82→        let tag_id = &modified_tag.tag;
 83→        let mut diff_status = DiffStatus::Added;
 84→        let mut baseline_value = None;
 85→
 86→        if let Some(baseline_tag) = baseline_map.get(tag_id) {
 87→            baseline_seen.insert(tag_id.clone());
 88→            // Compare values (for sequences, compare the sequence representation)
 89→            if baseline_tag.value == modified_tag.value {
 90→                diff_status = DiffStatus::Unchanged;
 91→            } else {
 92→                diff_status = DiffStatus::Changed;
 93→                baseline_value = Some(baseline_tag.value.clone());
 94→            }
 95→        }
 96→
 97→        // Clone modified_tag and set diff_status, preserving children
 98→        let mut result_tag = modified_tag.clone();
 99→        result_tag.diff_status = Some(diff_status);
100→        result_tag.baseline_value = baseline_value;
101→        result_tags.push(result_tag);
102→    }
103→
104→    // Add remaining baseline tags as Deleted
105→    for baseline_tag in &baseline_tags {
106→        if !baseline_seen.contains(&baseline_tag.tag) {
107→            let mut deleted_tag = baseline_tag.clone();
108→            deleted_tag.diff_status = Some(DiffStatus::Deleted);
109→            result_tags.push(deleted_tag);
110→        }
111→    }
112→
113→    result_tags.sort_by(|a, b| a.tag.cmp(&b.tag));
114→
115→    Ok(result_tags)
116→}
117→
118→fn extract_tags(obj: &FileDicomObject<InMemDicomObject>) -> Vec<DicomTag> {
119→    let mut tags = Vec::new();
120→
121→    for element in obj.meta().to_element_iter() {
122→        let tag = element.tag();
123→        let tag_str = format!("({:04X},{:04X})", tag.group(), tag.element());
124→
125→        let name = StandardDataDictionary
126→            .by_tag(tag)
127→            .map(|entry| entry.alias.to_string())
128→            .unwrap_or_default();
129→
130→        let vr = element.vr().to_string();
131→        let value = format_value(element.value());
132→
133→        tags.push(DicomTag {
134→            tag: tag_str,
135→            name,
136→            vr: vr.to_string(),
137→            value,
138→            baseline_value: None,
139→            depth: 0,
140→            is_expandable: false,
141→            is_expanded: false,
142→            children: Vec::new(),
143→            diff_status: None,
144→        });
145→    }
146→
147→    for element in obj {
148→        let tag = element.tag();
149→        let tag_str = format!("({:04X},{:04X})", tag.group(), tag.element());
150→
151→        let name = StandardDataDictionary
152→            .by_tag(tag)
153→            .map(|entry| entry.alias.to_string())
154→            .unwrap_or_default();
155→
156→        let vr = element.vr().to_string();
157→
158→        let (value, children, is_expandable) = if let Some(items) = element.value().items() {
159→            let children = extract_sequence_items(items, 1);
160→            let is_expandable = !children.is_empty();
161→            let value = format!("<Sequence with {} item(s)>", items.len());
162→            (value, children, is_expandable)
163→        } else {
164→            (format_value(element.value()), Vec::new(), false)
165→        };
166→
167→        tags.push(DicomTag {
168→            tag: tag_str,
169→            name,
170→            vr: vr.to_string(),
171→            value,
172→            baseline_value: None,
173→            depth: 0,
174→            is_expandable,
175→            is_expanded: false,
176→            children,
177→            diff_status: None,
178→        });
179→    }
180→
181→    tags
182→}
183→
184→fn extract_sequence_items(items: &[InMemDicomObject], depth: usize) -> Vec<DicomTag> {
185→    let mut children = Vec::new();
186→
187→    for (item_idx, item) in items.iter().enumerate() {
188→        let item_children = extract_tags_from_inmem_object(item, depth + 1);
189→        let item_header = DicomTag {
190→            tag: format!("Item #{}", item_idx + 1),
191→            name: String::new(),
192→            vr: String::new(),
193→            value: format!("<{} element(s)>", item.into_iter().count()),
194→            baseline_value: None,
195→            depth,
196→            is_expandable: !item_children.is_empty(),
197→            is_expanded: false,
198→            children: item_children,
199→            diff_status: None,
200→        };
201→        children.push(item_header);
202→    }
203→
204→    children
205→}
206→
207→fn extract_tags_from_inmem_object(obj: &InMemDicomObject, depth: usize) -> Vec<DicomTag> {
208→    let mut tags = Vec::new();
209→
210→    for element in obj {
211→        let tag = element.tag();
212→        let tag_str = format!("({:04X},{:04X})", tag.group(), tag.element());
213→
214→        let name = StandardDataDictionary
215→            .by_tag(tag)
216→            .map(|entry| entry.alias.to_string())
217→            .unwrap_or_default();
218→
219→        let vr = element.vr().to_string();
220→
221→        let (value, children, is_expandable) = if let Some(items) = element.value().items() {
222→            let children = extract_sequence_items(items, depth + 1);
223→            let is_expandable = !children.is_empty();
224→            let value = format!("<Sequence with {} item(s)>", items.len());
225→            (value, children, is_expandable)
226→        } else {
227→            (format_value(element.value()), Vec::new(), false)
228→        };
229→
230→        tags.push(DicomTag {
231→            tag: tag_str,
232→            name,
233→            vr: vr.to_string(),
234→            value,
235→            baseline_value: None,
236→            depth,
237→            is_expandable,
238→            is_expanded: false,
239→            children,
240→            diff_status: None,
241→        });
242→    }
243→
244→    tags
245→}
246→
247→fn format_value<I: HasLength, P>(value: &dicom::core::value::Value<I, P>) -> String {
248→    let value_str = if value.primitive().is_some() {
249→        value
250→            .to_str()
251→            .map(|c| c.into_owned())
252→            .unwrap_or_else(|_| "<Error>".to_string())
253→    } else if let Some(seq) = value.items() {
254→        format!("<Sequence with {} item(s)>", seq.len())
255→    } else if value.fragments().is_some() {
256→        "<Pixel Data Sequence>".to_string()
257→    } else {
258→        "<Unknown>".to_string()
259→    };
260→
261→    truncate_value(&value_str, 256)
262→}
263→
264→fn truncate_value(s: &str, max_len: usize) -> String {
265→    if s.len() > max_len {
266→        format!("{}...", &s[..max_len])
267→    } else {
268→        s.to_string()
269→    }
270→}
271→
272→fn first_value(s: &str) -> &str {
273→    s.split('\\').next().unwrap_or(s).trim()
274→}
275→
276→/// Returns (modified − baseline) in milliseconds for VR DA, TM, or DT; None otherwise or on parse error.
277→pub fn parse_dicom_datetime_delta_ms(vr: &str, baseline: &str, modified: &str) -> Option<i64> {
278→    let base = first_value(baseline);
279→    let mod_ = first_value(modified);
280→    match vr {
281→        "DA" => {
282→            let d1 = NaiveDate::parse_from_str(base, "%Y%m%d").ok()?;
283→            let d2 = NaiveDate::parse_from_str(mod_, "%Y%m%d").ok()?;
284→            let delta_days = (d2 - d1).num_days();
285→            Some(delta_days * 24 * 3600 * 1000)
286→        }
287→        "TM" => {
288→            let t1 = parse_tm(base)?;
289→            let t2 = parse_tm(mod_)?;
290→            // Time-of-day only: difference can be negative (e.g. 01:00 − 23:00).
291→            Some((t2 - t1).num_milliseconds())
292→        }
293→        "DT" => {
294→            let dt1 = parse_dt(base)?;
295→            let dt2 = parse_dt(mod_)?;
296→            Some((dt2 - dt1).num_milliseconds())
297→        }
298→        _ => None,
299→    }
300→}
301→
302→fn parse_tm(s: &str) -> Option<NaiveTime> {
303→    if s.contains('.') {
304→        NaiveTime::parse_from_str(s, "%H%M%S%.f").ok()
305→    } else {
306→        NaiveTime::parse_from_str(s, "%H%M%S").ok()
307→    }
308→}
309→
310→fn parse_dt(s: &str) -> Option<NaiveDateTime> {
311→    if s.contains('.') {
312→        NaiveDateTime::parse_from_str(s, "%Y%m%d%H%M%S%.f").ok()
313→    } else {
314→        NaiveDateTime::parse_from_str(s, "%Y%m%d%H%M%S").ok()
315→    }
316→}
