 66→    (tags::ROWS, "Rows"),
 67→    (tags::COLUMNS, "Columns"),
 68→    (tags::BITS_ALLOCATED, "BitsAllocated"),
 69→    (tags::BITS_STORED, "BitsStored"),
 70→    (tags::HIGH_BIT, "HighBit"),
