 83→// MR Image Module (M) - Type 1 tags (MR only)
 84→// Note: ScanOptions (0018,0022) is Type 2, not Type 1
 85→// Note: RepetitionTime and EchoTime are Type 1C (conditional), skipped
 86→const MR_IMAGE_TYPE1_TAGS: &[(Tag, &str)] = &[
 87→    (tags::IMAGE_TYPE, "ImageType"),
 88→    (tags::SCANNING_SEQUENCE, "ScanningSequence"),
 89→    (tags::SEQUENCE_VARIANT, "SequenceVariant"),
 90→    (tags::MR_ACQUISITION_TYPE, "MRAcquisitionType"),
