 92→
 93→pub fn validate_type1_fields<P: AsRef<Path>>(path: P) -> Result<ValidationResult, Box<dyn std::error::Error>> {
 94→    let obj = open_file(path)?;
 95→    
 96→    let sop_class_uid = obj
 97→        .element(tags::SOP_CLASS_UID)
 98→        .ok()
 99→        .and_then(|e| e.to_str().ok())
100→        .map(|s| s.trim().to_string());
101→    
102→    let sop_class_uid = match sop_class_uid {
103→        Some(uid) => uid,
104→        None => return Ok(ValidationResult::NotApplicable),
105→    };
106→    
107→    let modality_tags: &[(Tag, &str)] = if sop_class_uid == CT_IMAGE_STORAGE {
108→        CT_IMAGE_TYPE1_TAGS
109→    } else if sop_class_uid == MR_IMAGE_STORAGE {
110→        MR_IMAGE_TYPE1_TAGS
111→    } else {
112→        return Ok(ValidationResult::NotApplicable);
113→    };
114→    
115→    let mut missing_tags = Vec::new();
116→    
117→    for (tag, name) in SOP_COMMON_TYPE1_TAGS {
118→        if !is_tag_present(&obj, *tag) {
119→            missing_tags.push(name.to_string());
120→        }
121→    }
122→    
123→    for (tag, name) in GENERAL_STUDY_TYPE1_TAGS {
124→        if !is_tag_present(&obj, *tag) {
125→            missing_tags.push(name.to_string());
126→        }
127→    }
128→    
129→    for (tag, name) in GENERAL_SERIES_TYPE1_TAGS {
130→        if !is_tag_present(&obj, *tag) {
131→            missing_tags.push(name.to_string());
132→        }
133→    }
134→    
135→    for (tag, name) in FRAME_OF_REFERENCE_TYPE1_TAGS {
136→        if !is_tag_present(&obj, *tag) {
137→            missing_tags.push(name.to_string());
138→        }
139→    }
140→    
141→    for (tag, name) in IMAGE_PLANE_TYPE1_TAGS {
142→        if !is_tag_present(&obj, *tag) {
143→            missing_tags.push(name.to_string());
144→        }
145→    }
146→    
147→    for (tag, name) in IMAGE_PIXEL_TYPE1_TAGS {
148→        if !is_tag_present(&obj, *tag) {
149→            missing_tags.push(name.to_string());
150→        }
151→    }
152→    
153→    for (tag, name) in modality_tags {
154→        if !is_tag_present(&obj, *tag) {
155→            missing_tags.push(name.to_string());
156→        }
157→    }
158→    
159→    if missing_tags.is_empty() {
160→        Ok(ValidationResult::Valid)
161→    } else {
162→        Ok(ValidationResult::Invalid(missing_tags))
163→    }
164→}
165→
166→fn is_tag_present(obj: &FileDicomObject<InMemDicomObject>, tag: Tag) -> bool {
167→    obj.element(tag)
168→        .ok()
169→        .map(|e| {
170→            if let Ok(s) = e.to_str() {
171→                !s.trim().is_empty()
172→            } else {
173→                true
174→            }
175→        })
176→        .unwrap_or(false)
177→}
178→
179→pub fn get_sop_class<P: AsRef<Path>>(path: P) -> Result<SopClass, Box<dyn std::error::Error>> {
180→    let obj = open_file(path)?;
181→    
182→    let sop_class_uid = obj
183→        .element(tags::SOP_CLASS_UID)
184→        .ok()
185→        .and_then(|e| e.to_str().ok())
186→        .map(|s| s.trim().to_string());
187→    
188→    Ok(match sop_class_uid {
189→        Some(uid) if uid == CT_IMAGE_STORAGE => SopClass::Ct,
190→        Some(uid) if uid == MR_IMAGE_STORAGE => SopClass::Mr,
191→        Some(uid) => SopClass::Other(uid),
192→        None => SopClass::Unknown,
193→    })
