276→/// Returns (modified − baseline) in milliseconds for VR DA, TM, or DT; None otherwise or on parse error.
277→pub fn parse_dicom_datetime_delta_ms(vr: &str, baseline: &str, modified: &str) -> Option<i64> {
278→    let base = first_value(baseline);
279→    let mod_ = first_value(modified);
280→    match vr {
