  1→use crate::app::App;
  2→use crate::dicom::{parse_dicom_datetime_delta_ms, DiffStatus};
  3→use crate::validation::{SopClass, ValidationResult};
  4→use ratatui::{
  5→    layout::{Constraint, Direction, Layout, Rect},
  6→    style::{Color, Modifier, Style},
  7→    text::{Line, Span},
  8→    widgets::{Block, Borders, Cell, Paragraph, Row, Table},
  9→    Frame,
 10→};
 11→use similar::{ChangeTag, TextDiff};
 12→
 13→pub fn render(frame: &mut Frame, app: &mut App) {
 14→    let full_area = frame.area();
 15→
 16→    let validation_height = if matches!(&app.validation_result, ValidationResult::Invalid(_)) {
 17→        4
 18→    } else {
 19→        3
 20→    };
 21→
 22→    let chunks = Layout::default()
 23→        .direction(Direction::Vertical)
 24→        .constraints([Constraint::Min(5), Constraint::Length(validation_height)])
 25→        .split(full_area);
 26→
 27→    let area = chunks[0];
 28→    let validation_area = chunks[1];
 29→
 30→    render_validation_pane(frame, validation_area, app);
 31→
 32→    let mut header_cells = vec![];
 33→    if app.diff_mode {
 34→        header_cells.push(
 35→            Cell::from(" ").style(
 36→                Style::default()
 37→                    .fg(Color::Yellow)
 38→                    .add_modifier(Modifier::BOLD),
 39→            ),
 40→        );
 41→    }
 42→    header_cells.extend(vec![
 43→        Cell::from("  Tag").style(
 44→            Style::default()
 45→                .fg(Color::Yellow)
 46→                .add_modifier(Modifier::BOLD),
 47→        ),
 48→        Cell::from("Name").style(
 49→            Style::default()
 50→                .fg(Color::Yellow)
 51→                .add_modifier(Modifier::BOLD),
 52→        ),
 53→        Cell::from("VR").style(
 54→            Style::default()
 55→                .fg(Color::Yellow)
 56→                .add_modifier(Modifier::BOLD),
 57→        ),
 58→        Cell::from("Value").style(
 59→            Style::default()
 60→                .fg(Color::Yellow)
 61→                .add_modifier(Modifier::BOLD),
 62→        ),
 63→    ]);
 64→    let header = Row::new(header_cells).height(1);
 65→
 66→    let rows: Vec<Row> = app
 67→        .tags
 68→        .iter()
 69→        .map(|tag| {
 70→            let indent = "  ".repeat(tag.depth);
 71→            let expand_indicator = if tag.is_expandable {
 72→                if tag.is_expanded {
 73→                    "▼ "
 74→                } else {
 75→                    "▶ "
 76→                }
 77→            } else {
 78→                "  "
 79→            };
 80→            let tag_display = format!("{}{}{}", indent, expand_indicator, tag.tag);
 81→
 82→            // Determine styles based on diff status
 83→            let (row_style, value_cell) = if let Some(diff_status) = &tag.diff_status {
 84→                match diff_status {
 85→                    DiffStatus::Deleted => (
 86→                        Style::default().fg(Color::Red),
 87→                        Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Red)),
 88→                    ),
 89→                    DiffStatus::Added => (
 90→                        Style::default().fg(Color::Green),
 91→                        Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Green)),
 92→                    ),
 93→                    DiffStatus::Changed => {
 94→                        // Use inline diff if baseline_value is available
 95→                        let value_cell = if let Some(ref baseline) = tag.baseline_value {
 96→                            let mut line = render_inline_diff(baseline, &tag.value);
 97→                            if let Some(delta_ms) =
 98→                                parse_dicom_datetime_delta_ms(&tag.vr, baseline, &tag.value)
 99→                            {
100→                                let suffix = if delta_ms >= 0 {
101→                                    format!(" (+{} ms)", delta_ms)
102→                                } else {
103→                                    format!(" ({} ms)", delta_ms)
104→                                };
105→                                line.spans.push(Span::styled(
106→                                    suffix,
107→                                    Style::default().fg(Color::DarkGray),
108→                                ));
109→                            }
110→                            Cell::from(line)
111→                        } else {
112→                            // Fallback to simple blue text for backward compatibility
113→                            Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Blue))
114→                        };
115→                        (Style::default(), value_cell)
116→                    }
117→                    DiffStatus::Unchanged => (
118→                        Style::default(),
119→                        Cell::from(tag.value.as_str()).style(Style::default()),
120→                    ),
121→                }
122→            } else {
123→                // Normal mode: use private tag styling
124→                let base_style = if tag.is_private() {
125→                    Style::default().fg(Color::DarkGray)
126→                } else {
127→                    Style::default()
128→                };
129→                (base_style, Cell::from(tag.value.as_str()).style(base_style))
130→            };
131→
132→            let mut row_cells = vec![];
133→
134→            // Add diff indicator if in diff mode
135→            if app.diff_mode {
136→                let (indicator, indicator_style) = if let Some(diff_status) = &tag.diff_status {
137→                    match diff_status {
138→                        DiffStatus::Added => ("+", Style::default().fg(Color::Green)),
139→                        DiffStatus::Deleted => ("-", Style::default().fg(Color::Red)),
140→                        DiffStatus::Changed => ("M", Style::default().fg(Color::Blue)),
141→                        DiffStatus::Unchanged => (" ", Style::default()),
142→                    }
143→                } else {
144→                    (" ", Style::default())
145→                };
146→                row_cells.push(Cell::from(indicator).style(indicator_style));
147→            }
148→
149→            row_cells.extend(vec![
150→                Cell::from(tag_display).style(row_style),
151→                Cell::from(tag.name.as_str()).style(row_style),
152→                Cell::from(tag.vr.as_str()).style(row_style),
153→                value_cell,
154→            ]);
155→
156→            Row::new(row_cells)
157→        })
158→        .collect();
159→
160→    let widths: Vec<Constraint> = if app.diff_mode {
161→        vec![
162→            Constraint::Length(1),
163→            Constraint::Length(16),
164→            Constraint::Length(36),
165→            Constraint::Length(4),
166→            Constraint::Fill(1),
167→        ]
168→    } else {
169→        vec![
170→            Constraint::Length(16),
171→            Constraint::Length(36),
172→            Constraint::Length(4),
173→            Constraint::Fill(1),
174→        ]
175→    };
176→
177→    let title = if app.diff_mode {
178→        if let Some(ref modified_name) = app.modified_name {
179→            format!(" DICOM Diff: {} ↔ {} ", app.file_name, modified_name)
180→        } else {
181→            format!(" DICOM Diff: {} ", app.file_name)
182→        }
183→    } else {
184→        format!(" DICOM Viewer: {} ", app.file_name)
185→    };
186→
187→    let table = Table::new(rows, widths)
188→        .header(header)
