202→fn render_inline_diff(baseline: &str, modified: &str) -> Line<'static> {
203→    let diff = TextDiff::from_words(baseline, modified);
204→    let mut spans = Vec::new();
205→
206→    for change in diff.iter_all_changes() {
207→        let text = change.value();
208→        let style = match change.tag() {
209→            ChangeTag::Delete => Style::default()
210→                .fg(Color::Red)
211→                .bg(Color::DarkGray)
212→                .add_modifier(Modifier::CROSSED_OUT),
213→            ChangeTag::Insert => Style::default()
214→                .fg(Color::Green)
215→                .add_modifier(Modifier::BOLD),
216→            ChangeTag::Equal => Style::default(),
217→        };
218→        spans.push(Span::styled(text.to_string(), style));
219→    }
220→
221→    Line::from(spans)
222→}
