 15→
 16→/// DICOM TUI Viewer - View DICOM file tags in a terminal interface
 17→#[derive(Parser, Debug)]
 18→#[command(author, version, about, long_about = None)]
 19→struct Args {
 20→    /// Compare two DICOM files (baseline vs modified)
 21→    #[arg(short = 'd', long, value_names = ["BASELINE", "MODIFIED"], num_args = 2)]
 22→    diff: Option<Vec<PathBuf>>,
 23→
 24→    /// Path to the DICOM file to view (used when --diff is not specified)
 25→    #[arg(value_name = "FILE", required_unless_present = "diff")]
 26→    file: Option<PathBuf>,
 27→}
 28→
 29→fn main() -> Result<(), Box<dyn std::error::Error>> {
 30→    let args = Args::parse();
 31→
 32→    let (tags, file_name, modified_name, validation_result, sop_class, diff_mode) =
 33→        if let Some(diff_files) = &args.diff {
 34→            if diff_files.len() != 2 {
 35→                return Err("--diff requires exactly two file arguments".into());
 36→            }
 37→            let baseline_path = &diff_files[0];
 38→            let modified_path = &diff_files[1];
 39→
 40→            let tags = dicom::compare_dicom_files(baseline_path, modified_path)?;
 41→
 42→            let baseline_name = baseline_path
 43→                .file_name()
 44→                .map(|s| s.to_string_lossy().to_string())
 45→                .unwrap_or_else(|| baseline_path.to_string_lossy().to_string());
 46→            let modified_name = modified_path
 47→                .file_name()
 48→                .map(|s| s.to_string_lossy().to_string())
 49→                .unwrap_or_else(|| modified_path.to_string_lossy().to_string());
 50→
 51→            let sop_class =
 52→                validation::get_sop_class(baseline_path).unwrap_or(validation::SopClass::Unknown);
 53→            let validation_result = validation::validate_type1_fields(baseline_path)
 54→                .unwrap_or(validation::ValidationResult::NotApplicable);
 55→
 56→            (
 57→                tags,
 58→                baseline_name,
 59→                Some(modified_name),
 60→                validation_result,
 61→                sop_class,
 62→                true,
 63→            )
 64→        } else {
 65→            let file = args
 66→                .file
 67→                .ok_or("Either --diff with two files or a single file argument is required")?;
 68→            let tags = dicom::load_dicom_file(&file)?;
 69→
 70→            let sop_class =
 71→                validation::get_sop_class(&file).unwrap_or(validation::SopClass::Unknown);
 72→            let validation_result = validation::validate_type1_fields(&file)
 73→                .unwrap_or(validation::ValidationResult::NotApplicable);
 74→
 75→            let file_name = file
 76→                .file_name()
 77→                .map(|s| s.to_string_lossy().to_string())
 78→                .unwrap_or_else(|| file.to_string_lossy().to_string());
 79→
 80→            (tags, file_name, None, validation_result, sop_class, false)
 81→        };
 82→
 83→    let mut app = App::new_with_diff(
 84→        tags,
 85→        file_name,
 86→        modified_name,
 87→        validation_result,
 88→        sop_class,
 89→        diff_mode,
 90→    );
 91→
 92→    enable_raw_mode()?;
 93→    let mut stdout = io::stdout();
 94→    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
 95→    let backend = CrosstermBackend::new(stdout);
 96→    let mut terminal = Terminal::new(backend)?;
 97→
 98→    let result = run_app(&mut terminal, &mut app);
 99→
100→    disable_raw_mode()?;
101→    execute!(
102→        terminal.backend_mut(),
103→        LeaveAlternateScreen,
104→        DisableMouseCapture
105→    )?;
106→    terminal.show_cursor()?;
107→
108→    if let Err(err) = result {
109→        eprintln!("Error: {}", err);
110→        return Err(err.into());
111→    }
112→
113→    Ok(())
114→}
115→
116→fn run_app<B: Backend>(terminal: &mut Terminal<B>, app: &mut App) -> io::Result<()> {
117→    loop {
118→        terminal.draw(|frame| ui::render(frame, app))?;
119→
120→        app.handle_events()?;
121→
122→        if app.should_quit {
123→            return Ok(());
124→        }
125→    }
126→}
