```

Add the key handler for 'p' in the non-search-mode match:
```rust
KeyCode::Char('p') => {
    self.toggle_preview();
}
```

Add the `toggle_preview` method:
```rust
fn toggle_preview(&mut self) {
    self.show_preview = !self.show_preview;
    if self.show_preview && self.preview_image.is_none() && self.preview_error.is_none() {
        self.decode_preview();
    }
}

fn decode_preview(&mut self) {
    let Some(ref path) = self.dicom_file_path else {
        self.preview_error = Some("No file path available".into());
        return;
    };
    let Some(ref mut picker) = self.picker else {
        self.preview_error = Some("Terminal image protocol not detected".into());
        return;
    };

    match Self::load_preview_image(path) {
        Ok(dyn_img) => {
            let protocol = picker.new_resize_protocol(dyn_img);
            self.preview_image = Some(protocol);
        }
        Err(e) => {
            self.preview_error = Some(format!("Cannot decode pixel data: {}", e));
        }
    }
}
```

Add the static helper for DICOM pixel data decoding:
```rust
fn load_preview_image(path: &Path) -> Result<image::DynamicImage, Box<dyn std::error::Error>> {
    use dicom::object::open_file;
    use dicom_pixeldata::PixelDecoder;

    let obj = open_file(path)?;
    let pixel_data = obj.decode_pixel_data()?;
    let dyn_img = pixel_data.to_dynamic_image(0)?;
    Ok(dyn_img)
}
```

This uses default windowing (Window Center/Width from the file metadata, or full normalization if none present). The `to_dynamic_image(0)` call gets frame 0 (first/only frame for single-frame images).

#### Step 4: Modify `ui.rs` -- Preview pane layout

Update the `render` function to conditionally split the layout horizontally:

