    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([Constraint::Min(5), Constraint::Length(validation_height)])
        .split(main_area);

    // ... rest of existing render logic unchanged, using chunks[0] and chunks[1] ...
